import React, { useState, useRef, useCallback } from 'react';
import axios from 'axios';

// ─── Status chip colours ──────────────────────────────────────────────────────
const STATUS_META = {
  queued:     { label: 'Queued',      cls: 'chip-queued'     },
  uploading:  { label: 'Uploading…',  cls: 'chip-uploading'  },
  processing: { label: 'Processing…', cls: 'chip-processing' },
  completed:  { label: 'Done ✓',      cls: 'chip-completed'  },
  failed:     { label: 'Failed ✗',    cls: 'chip-failed'     },
};

// ─── Helpers ──────────────────────────────────────────────────────────────────
const fmtBytes = b => {
  if (b === 0) return '0 B';
  const k = 1024, units = ['B','KB','MB','GB'];
  const i = Math.floor(Math.log(b) / Math.log(k));
  return `${(b / Math.pow(k, i)).toFixed(1)} ${units[i]}`;
};

const uid = () => Math.random().toString(36).slice(2);

// ─────────────────────────────────────────────────────────────────────────────
export default function App() {
  const inputRef = useRef(null);

  // List of { id, name, size, status, downloadUrl, error }
  const [files, setFiles]           = useState([]);
  const [uploadPct, setUploadPct]   = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [dragOver, setDragOver]     = useState(false);

  // ── Derived stats ────────────────────────────────────────────────────────
  const total     = files.length;
  const completed = files.filter(f => f.status === 'completed').length;
  const failed    = files.filter(f => f.status === 'failed').length;
  const progress  = total === 0 ? 0 : Math.round((completed + failed) / total * 100);

  // ── File selection ───────────────────────────────────────────────────────
  const addFiles = useCallback(incoming => {
    const valid = [...incoming].filter(f =>
      f.name.toLowerCase().endsWith('.m4a')
    );
    const invalid = incoming.length - valid.length;
    if (invalid > 0) alert(`${invalid} file(s) skipped — only .m4a files are accepted.`);
    if (valid.length === 0) return;

    setFiles(prev => [
      ...prev,
      ...valid.map(f => ({
        id:          uid(),
        name:        f.name,
        size:        f.size,
        status:      'queued',
        downloadUrl: null,
        error:       null,
        _file:       f,       // keep reference for FormData
      })),
    ]);
  }, []);

  const onInputChange = e => addFiles(e.target.files);

  const onDrop = e => {
    e.preventDefault();
    setDragOver(false);
    addFiles(e.dataTransfer.files);
  };

  // ── Remove a single file before upload ──────────────────────────────────
  const removeFile = id => {
    if (isSubmitting) return;
    setFiles(prev => prev.filter(f => f.id !== id));
  };

  // ── Clear all ────────────────────────────────────────────────────────────
  const clearAll = () => {
    if (isSubmitting) return;
    setFiles([]);
    setUploadPct(0);
    if (inputRef.current) inputRef.current.value = '';
  };

  // ── Upload & convert ─────────────────────────────────────────────────────
  const handleConvert = async () => {
    const queued = files.filter(f => f.status === 'queued');
    if (queued.length === 0) return;

    setIsSubmitting(true);
    setUploadPct(0);

    // Mark all queued as uploading
    setFiles(prev =>
      prev.map(f => f.status === 'queued' ? { ...f, status: 'uploading' } : f)
    );

    const form = new FormData();
    queued.forEach(f => form.append('files', f._file));

    try {
      const { data } = await axios.post('/convert', form, {
        headers: { 'Content-Type': 'multipart/form-data' },
        onUploadProgress: e => {
          const pct = e.total ? Math.round((e.loaded / e.total) * 100) : 0;
          setUploadPct(pct);
          // Once upload is done mark all as processing
          if (pct === 100) {
            setFiles(prev =>
              prev.map(f => f.status === 'uploading' ? { ...f, status: 'processing' } : f)
            );
          }
        },
      });

      // Reconcile server results with local state by original filename
      setFiles(prev =>
        prev.map(localFile => {
          const match = data.conversions.find(r => r.file === localFile.name);
          if (!match) return localFile;
          return {
            ...localFile,
            status:      match.status,
            downloadUrl: match.download_url || null,
            error:       match.error || null,
          };
        })
      );
    } catch (err) {
      const msg = err.response?.data?.error || err.message;
      // Mark all still-processing/uploading as failed
      setFiles(prev =>
        prev.map(f =>
          ['uploading', 'processing'].includes(f.status)
            ? { ...f, status: 'failed', error: msg }
            : f
        )
      );
    } finally {
      setIsSubmitting(false);
    }
  };

  // ─────────────────────────────────────────────────────────────────────────
  return (
    <div className="app">
      {/* ── Header ── */}
      <header className="header">
        <div className="logo">
          <span className="logo-icon">🎵</span>
          <div>
            <h1>M4A → MP3</h1>
            <p>Professional batch audio converter</p>
          </div>
        </div>
        <div className="header-stats">
          <span className="stat"><b>{total}</b> selected</span>
          <span className="stat chip-completed"><b>{completed}</b> done</span>
          {failed > 0 && <span className="stat chip-failed"><b>{failed}</b> failed</span>}
        </div>
      </header>

      {/* ── Drop Zone ── */}
      <div
        className={`drop-zone ${dragOver ? 'active' : ''}`}
        onClick={() => !isSubmitting && inputRef.current.click()}
        onDragOver={e => { e.preventDefault(); setDragOver(true); }}
        onDragLeave={() => setDragOver(false)}
        onDrop={onDrop}
      >
        <div className="drop-icon">📂</div>
        <p className="drop-title">Drop your .m4a files here</p>
        <p className="drop-sub">or click to browse — up to 50 files, 300 MB each</p>
        <input
          ref={inputRef}
          type="file"
          multiple
          accept=".m4a"
          style={{ display: 'none' }}
          onChange={onInputChange}
        />
      </div>

      {/* ── Action bar ── */}
      {files.length > 0 && (
        <div className="action-bar">
          <button
            className="btn btn-primary"
            onClick={handleConvert}
            disabled={isSubmitting || files.every(f => f.status !== 'queued')}
          >
            {isSubmitting ? 'Converting…' : `Convert ${files.filter(f => f.status === 'queued').length} file(s)`}
          </button>
          <button className="btn btn-ghost" onClick={clearAll} disabled={isSubmitting}>
            Clear All
          </button>
        </div>
      )}

      {/* ── Upload progress bar ── */}
      {isSubmitting && (
        <div className="progress-wrap">
          <div className="progress-labels">
            <span>Uploading…</span>
            <span>{uploadPct}%</span>
          </div>
          <div className="progress-track">
            <div className="progress-fill upload-fill" style={{ width: `${uploadPct}%` }} />
          </div>
        </div>
      )}

      {/* ── Overall conversion progress ── */}
      {total > 0 && (
        <div className="progress-wrap">
          <div className="progress-labels">
            <span>Overall progress</span>
            <span>{completed + failed} / {total}</span>
          </div>
          <div className="progress-track">
            <div
              className="progress-fill"
              style={{
                width: `${progress}%`,
                background: failed > 0
                  ? 'linear-gradient(90deg,#6c63ff,#e74c5e)'
                  : 'linear-gradient(90deg,#6c63ff,#43e5f7)',
              }}
            />
          </div>
        </div>
      )}

      {/* ── File table ── */}
      {files.length > 0 && (
        <div className="table-wrap">
          <table className="file-table">
            <thead>
              <tr>
                <th>#</th>
                <th>File Name</th>
                <th>Size</th>
                <th>Status</th>
                <th>Action</th>
              </tr>
            </thead>
            <tbody>
              {files.map((f, i) => (
                <tr key={f.id} className={f.status === 'completed' ? 'row-done' : ''}>
                  <td className="td-num">{i + 1}</td>
                  <td className="td-name" title={f.name}>{f.name}</td>
                  <td className="td-size">{fmtBytes(f.size)}</td>
                  <td>
                    <span className={`chip ${STATUS_META[f.status]?.cls || ''}`}>
                      {STATUS_META[f.status]?.label || f.status}
                    </span>
                    {f.error && <span className="err-tip" title={f.error}> ⚠</span>}
                  </td>
                  <td>
                    {f.status === 'completed' && f.downloadUrl ? (
                      <a
                        className="btn btn-sm btn-download"
                        href={f.downloadUrl}
                        download
                        target="_blank"
                        rel="noreferrer"
                      >
                        ⬇ Download
                      </a>
                    ) : f.status === 'queued' ? (
                      <button
                        className="btn btn-sm btn-remove"
                        onClick={() => removeFile(f.id)}
                      >
                        ✕
                      </button>
                    ) : '—'}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* ── Empty state ── */}
      {files.length === 0 && (
        <div className="empty-state">
          <p>No files selected yet. Add some .m4a files to get started.</p>
        </div>
      )}

      <footer className="footer">
        Converted files are automatically deleted after 1 hour &nbsp;·&nbsp; Max 50 files per batch
      </footer>
    </div>
  );
}
